package com.example.samlsp.service;

import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

@Service
public class SamlService {

    public Map<String, String> processSamlResponse(String samlResponseBase64) {
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
            String samlXml = new String(decodedBytes, StandardCharsets.UTF_8);

            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true); // Important for XPath with namespaces
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document doc = builder.parse(new ByteArrayInputStream(samlXml.getBytes(StandardCharsets.UTF_8)));

            XPath xpath = XPathFactory.newInstance().newXPath();

            // Extract NameID (username)
            String nameId = (String) xpath.evaluate(
                    "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='Subject']/*[local-name()='NameID']/text()",
                    doc, XPathConstants.STRING);

            if (nameId == null || nameId.isEmpty()) {
                throw new RuntimeException("NameID not found in SAML Assertion.");
            }

            Map<String, String> userAttributes = new HashMap<>();
            userAttributes.put("username", nameId);

            // Extract Attributes
            NodeList attributeNodes = (NodeList) xpath.evaluate(
                    "/*[local-name()='Response']/*[local-name()='Assertion']/*[local-name()='AttributeStatement']/*[local-name()='Attribute']",
                    doc, XPathConstants.NODESET);

            for (int i = 0; i < attributeNodes.getLength(); i++) {
                Element attributeElement = (Element) attributeNodes.item(i);
                String attributeName = attributeElement.getAttribute("Name");
                String attributeValue = (String) xpath.evaluate(
                        "*[local-name()='AttributeValue']/text()",
                        attributeElement, XPathConstants.STRING);
                if (attributeName != null && !attributeName.isEmpty() && attributeValue != null && !attributeValue.isEmpty()) {
                    userAttributes.put(attributeName, attributeValue);
                }
            }

            // Create an authenticated session
            Authentication authentication = new UsernamePasswordAuthenticationToken(
                    nameId,
                    null, // No credentials for SAML
                    Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER")) // Assign a default role
            );
            SecurityContextHolder.getContext().setAuthentication(authentication);

            return userAttributes;

        } catch (Exception e) {
            throw new RuntimeException("Error processing SAML response: " + e.getMessage(), e);
        }
    }
}

